const handleScan = e => {
  if (e.key !== 'Enter') return
  const query = e.target.value.trim()
  if (!query) return

  /* 1) пытаемся как код */
  let item = goods.find(g => g.code === query)

  /* 2) если не нашли – ищем по названию (без регистра) */
  if (!item) {
    const matches = goods.filter(g =>
      g.name.toLowerCase().includes(query.toLowerCase())
    )

    if (matches.length === 0) {
      alert('Товар не найден')
      e.target.value = ''
      return
    }
    if (matches.length > 1) {
      alert(
        'Найдено несколько товаров:\n' +
        matches.map(m => `• ${m.name} (код ${m.code})`).join('\n') +
        '\nОтсканируйте штрих-код нужного.'
      )
      e.target.value = ''
      return
    }
    /* тут exactly one match */
    item = matches[0]
  }

  /* 3) добавляем/увеличиваем позицию в корзине */
  setCart(prev => {
    const ex = prev.find(p => p.id === item.id)
    return ex
      ? prev.map(p => p.id === item.id ? { ...p, qty: p.qty + 1 } : p)
      : [...prev, { ...item, qty: 1 }]
  })
  e.target.value = ''
}
